const raw = $json.choices?.[0]?.message?.content || "";

const topics = raw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line)
  .map(line => line.replace(/^\d+[\.\)]\s*/, "").trim())
  .filter(line => line.length > 0)
  .slice(0, 5);

return [{ json: { raw, topics } }];

const raw = $json.choices?.[0]?.message?.content || "";

const hooks = raw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line)
  .map(line => line.replace(/^\d+[\.\)]\s*/, "").trim())
  .filter(line => line.length > 0)
  .slice(0, 3);

return {
  topic: $('rename topic').item.json.topic,
  raw_hooks: raw,
  hooks
};

const script = $json.choices?.[0]?.message?.content || "";

return {
  topic: $('rename_hook').item.json.topic,
  hook: $('rename_hook').item.json.hook,
  script: script.trim()
};

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 60);
}

const today = new Date().toISOString().slice(0, 10);

return {
  date: today,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: slugify($json.topic),
  hook_slug: slugify($json.hook)
};

