const fs = require('fs');
const path = require('path');

// Split script into sentences
const script = $json.script;
const sentences = script
  .split(/(?<=[.!?])\s+/)
  .map(s => s.trim())
  .filter(s => s.length > 0);

// Estimate ~2.5 words per second for TTS
const wordsPerSecond = 2.5;

function toSrtTime(seconds) {
  const h = Math.floor(seconds / 3600).toString().padStart(2, '0');
  const m = Math.floor((seconds % 3600) / 60).toString().padStart(2, '0');
  const s = Math.floor(seconds % 60).toString().padStart(2, '0');
  const ms = Math.floor((seconds % 1) * 1000).toString().padStart(3, '0');
  return `${h}:${m}:${s},${ms}`;
}

let srtContent = '';
let currentTime = 0;

sentences.forEach((sentence, index) => {
  const wordCount = sentence.split(' ').length;
  const duration = Math.max(1.5, wordCount / wordsPerSecond);
  const endTime = currentTime + duration;

  srtContent += `${index + 1}\n`;
  srtContent += `${toSrtTime(currentTime)} --> ${toSrtTime(endTime)}\n`;
  srtContent += `${sentence}\n\n`;

  currentTime = endTime + 0.1;
});

const filename = `${$json.date}_${$json.slug}_${$json.variant}.srt`;
const filepath = `/files/subs/${filename}`;
const dir = path.dirname(filepath);

if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

fs.writeFileSync(filepath, srtContent, 'utf8');

return {
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: $json.slug,
  hook_slug: $json.hook_slug,
  variant: $json.variant,
  voice_id: $json.voice_id,
  script_file: $json.script_file,
  audio_file: $json.audio_file,
  srt_file: filepath
};

